using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyFunctionApp
{
    public class ReportingApiController : ControllerBase
    {
        private readonly ILogger _logger;
        private readonly IConfiguration _config;

        public ReportingApiController(ILogger<ReportingApiController> logger, IConfiguration config)
        {
            _logger = logger;
            _config = config;
        }

        [HttpGet]
        [Route("report")]
        public IActionResult GetReports([FromQuery] string queryString)
        {
            var sqlConnectionString = _config["SqlConnectionString"];

            // Build the dynamic SQL query from the query string parameters
            var query = "SELECT * FROM Reports";
            if (queryString.Contains("date"))
            {
                var dateParam = queryString["date"].ToString();
                query += $" WHERE Date = '{dateParam}'";
            }

            // Execute the SQL query and return the results as JSON
            using (var connection = new SqlConnection(sqlConnectionString))
            {
                var result = connection.Query<Report>(query).ToList();
                return Ok(result);
            }
        }
    }
